#include <iostream>
using namespace std;

// Base class
class Calculator {
public:
    // Overloaded functions - same name, different parameters
    int add(int a, int b) {
        return a + b;
    }

    double add(double a, double b) {
        return a + b;
    }

    int add(int a, int b, int c) {
        return a + b + c;
    }

    string add(string a, string b) {
        return a + b;
    }
};

int main() {
    Calculator calc;

    cout << "Integer addition: " << calc.add(5, 3) << endl;
    cout << "Double addition: " << calc.add(2.5, 3.7) << endl;
    cout << "Triple addition: " << calc.add(1, 2, 3) << endl;
    cout << "String addition: " << calc.add("Hello ", "World") << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

// Base class
class Animal {
protected:
    string name;
public:
    Animal(string n) : name(n) {}

    // Virtual function - can be overridden
    virtual void speak() {
        cout << name << " makes a sound" << endl;
    }

    // Virtual destructor - important for proper cleanup
    virtual ~Animal() {}
};

// Derived class 1
class Dog : public Animal {
public:
    Dog(string n) : Animal(n) {}

    void speak() override {
        cout << name << " says: Woof! Woof!" << endl;
    }
};

// Derived class 2
class Cat : public Animal {
public:
    Cat(string n) : Animal(n) {}

    void speak() override {
        cout << name << " says: Meow! Meow!" << endl;
    }
};

// Derived class 3
class Cow : public Animal {
public:
    Cow(string n) : Animal(n) {}

    void speak() override {
        cout << name << " says: Moo! Moo!" << endl;
    }
};

int main() {
    // Create objects
    Dog dog("Buddy");
    Cat cat("Whiskers");
    Cow cow("Daisy");

    // Using base class pointer - runtime polymorphism
    Animal* animals[3];
    animals[0] = &dog;
    animals[1] = &cat;
    animals[2] = &cow;

    cout << "=== Runtime Polymorphism Demo ===" << endl;
    for (int i = 0; i < 3; i++) {
        animals[i]->speak();  // Calls appropriate derived class method
    }

    cout << "\n=== Using References ===" << endl;
    Animal& ref1 = dog;
    Animal& ref2 = cat;
    ref1.speak();
    ref2.speak();

    return 0;
}

#include <iostream>
#include <vector>
#include <memory>
using namespace std;

// Abstract base class (interface) - cannot be instantiated
class Shape {
protected:
    string color;
public:
    Shape(string c) : color(c) {}

    // Pure virtual function - must be overridden
    virtual double area() const = 0;
    virtual double perimeter() const = 0;
    virtual void display() const = 0;

    // Virtual destructor
    virtual ~Shape() {}
};

// Derived class - Circle
class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r, string c) : Shape(c), radius(r) {}

    double area() const override {
        return 3.14159 * radius * radius;
    }

    double perimeter() const override {
        return 2 * 3.14159 * radius;
    }

    void display() const override {
        cout << "Circle [Color: " << color 
             << ", Radius: " << radius 
             << ", Area: " << area() 
             << ", Perimeter: " << perimeter() << "]" << endl;
    }
};

// Derived class - Rectangle
class Rectangle : public Shape {
private:
    double length, width;
public:
    Rectangle(double l, double w, string c) : Shape(c), length(l), width(w) {}

    double area() const override {
        return length * width;
    }

    double perimeter() const override {
        return 2 * (length + width);
    }

    void display() const override {
        cout << "Rectangle [Color: " << color 
             << ", L: " << length 
             << ", W: " << width
             << ", Area: " << area() 
             << ", Perimeter: " << perimeter() << "]" << endl;
    }
};

// Derived class - Triangle
class Triangle : public Shape {
private:
    double a, b, c;
public:
    Triangle(double x, double y, double z, string c) : Shape(c), a(x), b(y), c(z) {}

    double area() const override {
        double s = (a + b + c) / 2;
        return sqrt(s * (s - a) * (s - b) * (s - c)); // Heron's formula
    }

    double perimeter() const override {
        return a + b + c;
    }

    void display() const override {
        cout << "Triangle [Color: " << color 
             << ", Sides: " << a << ", " << b << ", " << c
             << ", Area: " << area() 
             << ", Perimeter: " << perimeter() << "]" << endl;
    }
};

int main() {
    // Using smart pointers for automatic memory management
    vector<unique_ptr<Shape>> shapes;

    shapes.push_back(make_unique<Circle>(5.0, "Red"));
    shapes.push_back(make_unique<Rectangle>(4.0, 6.0, "Blue"));
    shapes.push_back(make_unique<Triangle>(3.0, 4.0, 5.0, "Green"));

    cout << "=== Polymorphism with Abstract Classes ===" << endl;
    cout << "Total Shapes: " << shapes.size() << endl << endl;

    double totalArea = 0;
    for (auto& shape : shapes) {
        shape->display();
        totalArea += shape->area();
    }

    cout << "\nTotal Area of all shapes: " << totalArea << endl;

    return 0;
}
